"use strict";(self.webpackChunktmp_docusaurus_temp=self.webpackChunktmp_docusaurus_temp||[]).push([["3702"],{6429(n){n.exports=JSON.parse('{"archive":{"blogPosts":[{"id":"ai-blog-workflow","metadata":{"permalink":"/blog/notes/ai-blog-workflow","source":"@site/blog/notes/2026-04-09-ai-workflow.md","title":"\u7528 AI \u7BA1\u6211\u7684\u6280\u8853\u90E8\u843D\u683C\uFF1ADocusaurus + GitHub Actions + AI \u5DE5\u4F5C\u6D41","description":"\u9019\u7BC7\u63A2\u7D22\u7B46\u8A18\u8A18\u9304\u6211\u600E\u9EBC\u7528 Docusaurus v3 \u5EFA\u9019\u500B\u90E8\u843D\u683C\uFF0C\u4EE5\u53CA\u628A AI \u6574\u9032\u5BEB\u4F5C\u6D41\u7A0B\u7684\u65B9\u6CD5\u3002","date":"2026-04-09T00:00:00.000Z","tags":[{"inline":true,"label":"\u5DE5\u5177\u8A66\u7528","permalink":"/blog/notes/tags/\u5DE5\u5177\u8A66\u7528"},{"inline":true,"label":"GitHub\u7BC4\u4F8B","permalink":"/blog/notes/tags/git-hub\u7BC4\u4F8B"},{"inline":true,"label":"AI\u61C9\u7528","permalink":"/blog/notes/tags/ai\u61C9\u7528"}],"readingTime":1.02,"hasTruncateMarker":true,"authors":[{"name":"wz-cch","title":"\u5E73\u53F0\u5DE5\u7A0B\u5E2B","url":"https://www.linkedin.com/in/chien-hsiang-chen-2378b1255/","imageURL":"https://github.com/wz-cch.png","key":"wz-cch","page":null}],"frontMatter":{"slug":"ai-blog-workflow","title":"\u7528 AI \u7BA1\u6211\u7684\u6280\u8853\u90E8\u843D\u683C\uFF1ADocusaurus + GitHub Actions + AI \u5DE5\u4F5C\u6D41","date":"2026-04-09T00:00:00.000Z","authors":"wz-cch","tags":["\u5DE5\u5177\u8A66\u7528","GitHub\u7BC4\u4F8B","AI\u61C9\u7528"]},"unlisted":false},"content":"\u9019\u7BC7\u63A2\u7D22\u7B46\u8A18\u8A18\u9304\u6211\u600E\u9EBC\u7528 Docusaurus v3 \u5EFA\u9019\u500B\u90E8\u843D\u683C\uFF0C\u4EE5\u53CA\u628A AI \u6574\u9032\u5BEB\u4F5C\u6D41\u7A0B\u7684\u65B9\u6CD5\u3002\\n\\n\x3c!-- truncate --\x3e\\n\\n## \u6280\u8853\u9078\u578B\\n\\n| \u9805\u76EE | \u9078\u64C7 | \u7406\u7531 |\\n|------|------|------|\\n| \u6846\u67B6 | Docusaurus v3 | TypeScript \u652F\u63F4\u4F73\uFF0CMDX\uFF0CSEO \u53CB\u5584 |\\n| \u90E8\u7F72 | GitHub Pages | \u514D\u8CBB\uFF0C\u642D\u914D Actions \u96F6\u7DAD\u904B |\\n| \u81EA\u52D5\u5316 | GitHub Actions | push main \u5373\u81EA\u52D5\u90E8\u7F72 |\\n| \u4E3B\u984C | classic + \u81EA\u8A02 CSS | \u4E0D\u60F3\u4F9D\u8CF4\u7B2C\u4E09\u65B9\u4E3B\u984C\u5957\u4EF6 |\\n\\n## \u5C08\u6848\u7D50\u69CB\\n\\n```\\nblog/\\n\u251C\u2500\u2500 blog/\\n\u2502   \u251C\u2500\u2500 tech/       # \u6280\u8853\u6587\u7AE0\\n\u2502   \u251C\u2500\u2500 notes/      # \u63A2\u7D22\u7B46\u8A18\\n\u2502   \u2514\u2500\u2500 life/       # \u9592\u804A\\n\u251C\u2500\u2500 src/\\n\u2502   \u251C\u2500\u2500 pages/      # \u81EA\u8A02\u9801\u9762\uFF08\u9996\u9801\u3001\u95DC\u65BC\u6211\uFF09\\n\u2502   \u2514\u2500\u2500 css/        # \u5168\u57DF\u6A23\u5F0F\\n\u251C\u2500\u2500 docusaurus.config.ts\\n\u2514\u2500\u2500 .github/workflows/deploy.yml\\n```\\n\\n## \u591A blog \u8A2D\u5B9A\u65B9\u5F0F\\n\\nDocusaurus v3 \u7528\u4E00\u500B preset \u653E\u4E3B\u8981 blog\uFF0C\u5176\u4ED6 blog \u7528 plugin \u8FFD\u52A0\uFF1A\\n\\n```typescript\\n// docusaurus.config.ts\\npresets: [[\'classic\', { blog: { path: \'./blog/tech\', routeBasePath: \'tech\' } }]],\\nplugins: [\\n  [\'@docusaurus/plugin-content-blog\', { id: \'notes\', path: \'./blog/notes\', routeBasePath: \'notes\' }],\\n  [\'@docusaurus/plugin-content-blog\', { id: \'life\',  path: \'./blog/life\',  routeBasePath: \'life\'  }],\\n]\\n```\\n\\n## AI \u5BEB\u4F5C\u6D41\u7A0B\\n\\n```\\n\u8349\u7A3F\uFF08\u4E2D\u6587\u53E3\u8A9E\uFF09-> AI \u6F64\u7A3F -> Review -> commit -> \u81EA\u52D5\u90E8\u7F72\\n```\\n\\n\u5BE6\u969B\u4E0A AI \u4E3B\u8981\u505A\uFF1A\\n1. \u88DC\u5145\u6BB5\u843D\u7D50\u69CB\\n2. \u6574\u7406 bullet point\\n3. \u52A0\u5C0F\u6A19\u8B93\u6587\u7AE0\u66F4\u597D\u6383\\n\\n\u5167\u5BB9\u5224\u65B7\u9084\u662F\u6211\u4F86\uFF0CAI \u4E0D\u77E5\u9053\u6211\u8E29\u904E\u54EA\u4E9B\u5751\u3002\\n\\n## \u539F\u59CB\u78BC\\n\\n\u9019\u500B\u90E8\u843D\u683C\u672C\u8EAB\u5C31\u662F GitHub public repo\uFF1A[wz-cch/blog](https://github.com/wz-cch/blog)"}]}}')}}]);